public boolean canConstruct(String s) {
    int n = s.length();
    for (int i = n / 2; i > 0; --i) {
        if (n % i == 0) {
            String substr = s.substring(0, i);
            boolean flag = true;
            for (int j = i; j < n; j += i) {
                if (!s.substring(j, j + i).equals(substr)) {
                    flag = false;
                    break;
                }
            }

            if (flag) return true;
        }
    }
    return false;
}
```


